import{_ as r,C as h,o as e,c as i,a2 as a,b as s,w as l,a as u,E as q,a3 as n}from"./chunks/framework.Crpw6aS5.js";const E=JSON.parse('{"title":"航空公司教训","description":"投资生涯最深刻的错误之一，最糟糕的生意模式","frontmatter":{"title":"航空公司教训","description":"投资生涯最深刻的错误之一，最糟糕的生意模式"},"headers":[],"relativePath":"02_concepts/airline-lessons.md","filePath":"02_concepts/airline-lessons.md"}'),c={name:"02_concepts/airline-lessons.md"};function d(p,t,b,f,m,_){const o=h("Mermaid");return e(),i("div",null,[t[1]||(t[1]=a('<h1 id="航空公司教训" tabindex="-1">航空公司教训 <a class="header-anchor" href="#航空公司教训" aria-label="Permalink to &quot;航空公司教训&quot;">​</a></h1><blockquote><p>&quot;最糟糕的企业就是那种增长很快，需要大量资本才能实现增长，然后赚不到什么钱。想想航空公司。&quot; —— <a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2007年</p></blockquote><p>1989年，巴菲特以&quot;我知道航空公司在赚什么钱&quot;的自信买入了<a href="/search.html?q=美国航空">美国航空</a>优先股。1991年，这笔投资差点归零。这是他投资生涯中最重要的错误之一，也是理解&quot;最糟糕生意模式&quot;的最佳教材。</p><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1989年/核心总结</td><td style="text-align:left;">1989年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1991年/核心总结</td><td style="text-align:left;">1991年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1994年/核心总结</td><td style="text-align:left;">1994年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1998年/核心总结</td><td style="text-align:left;">1998年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2007年/核心总结</td><td style="text-align:left;">2007年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2013年/核心总结</td><td style="text-align:left;">2013年]]**</td></tr></tbody></table><hr><h2 id="一、买入-1989年的决定" tabindex="-1">一、买入：1989年的决定 <a class="header-anchor" href="#一、买入-1989年的决定" aria-label="Permalink to &quot;一、买入：1989年的决定&quot;">​</a></h2><p>1989年夏天，巴菲特卖出了中期免税债券，买入了三家可转换优先股：</p><blockquote><p>&quot;我们夏天买了六亿六千万<a href="/03_companies/吉列.html">吉列</a>，八年强制赎回，股息八又四分之三，五十块转股，然后三亿五千八百万<a href="/search.html?q=美国航空">美国航空</a>，九年赎回，股息九又四分之一，六十块转股，三亿冠军国际，九年赎回，股息九又四分之一，三十八块转股。&quot;</p></blockquote><blockquote><p>&quot;和传统可转优先股不一样，我们买这些不能短期卖，一段时间不能转，所以短期价格波动赚不到钱。我们最终赚钱还是要看企业长期经营结果好不好。我们不知道投行、航空、造纸未来经济怎么样，我们不是无神论，我们是不可知论，我们没有强烈 conviction。&quot;</p></blockquote><hr><h2 id="二、危机-成本结构的致命缺陷" tabindex="-1">二、危机：成本结构的致命缺陷 <a class="header-anchor" href="#二、危机-成本结构的致命缺陷" aria-label="Permalink to &quot;二、危机：成本结构的致命缺陷&quot;">​</a></h2><p>1991年，美国航空优先股价值大幅低于成本。巴菲特直言：错在我。</p><blockquote><p>&quot;我们<a href="/search.html?q=美国航空">美国航空</a>优先股价值低于成本，因为航空业全行业亏，破产公司还在运营，所以正常公司竞争不过，因为破产公司不用承担过去成本，能低价卖票，把整个行业价格拉下来。&quot;</p></blockquote><blockquote><p>&quot;所以我们<a href="/search.html?q=美国航空">美国航空</a>投资减值了。CEO塞斯努力调整，能不能活下来还不好说。我们已经减值了。不对，不对，错在我。&quot;</p></blockquote><hr><h2 id="三、反思-为何这笔投资错了" tabindex="-1">三、反思：为何这笔投资错了 <a class="header-anchor" href="#三、反思-为何这笔投资错了" aria-label="Permalink to &quot;三、反思：为何这笔投资错了&quot;">​</a></h2><p>1994年信中，巴菲特进行了深刻的自省：</p><blockquote><p>&quot;在这次购买之前，我根本没有关注那些成本高昂且极难降低的航空公司将不可避免地会遇到的问题。早些年，这些威胁生命的成本几乎没有造成什么问题。航空公司当时受到监管的保护免受竞争，运营商可以吸收高成本，因为他们可以通过同样高的票价将其转嫁出去。&quot;</p></blockquote><blockquote><p>&quot;当放松管制来临时，它并没有立即改变局面：低成本运营商的运力很小，高成本航空公司可以在很大程度上维持其现有的票价结构。在此期间，长期问题很大程度上不可见但缓慢转移，不可持续的成本进一步嵌入。&quot;</p></blockquote><blockquote><p>&quot;随着低成本运营商的运力扩张，他们的票价开始迫使老牌高成本航空公司削减自己的票价。最终经济学的基本原理占了上风：在不受监管的大宗商品业务中，公司必须将其成本降低到竞争水平或面临灭绝。这个原则对你的董事长来说应该是显而易见的，但我错过了它。&quot;</p></blockquote><hr><h2 id="四、幸运脱身-1998年高价卖出" tabindex="-1">四、幸运脱身：1998年高价卖出 <a class="header-anchor" href="#四、幸运脱身-1998年高价卖出" aria-label="Permalink to &quot;四、幸运脱身：1998年高价卖出&quot;">​</a></h2><blockquote><p>&quot;我，说出来惭愧，1989年我也参与了这种愚蠢，让<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>买入了<a href="/search.html?q=美国航空">美国航空</a>优先股。墨水还没干，公司就开始螺旋下降，很快分红就停了。后来我们非常幸运，1998年居然能高价卖掉股份，赚了一笔。&quot;</p></blockquote><blockquote><p>&quot;我卖出之后十年，公司破产了两次。&quot;</p></blockquote><hr><h2 id="五、2007年最经典的总结-三种储蓄账户" tabindex="-1">五、2007年最经典的总结：三种储蓄账户 <a class="header-anchor" href="#五、2007年最经典的总结-三种储蓄账户" aria-label="Permalink to &quot;五、2007年最经典的总结：三种储蓄账户&quot;">​</a></h2><blockquote><p>&quot;总结一下，想想三种储蓄账户：</p></blockquote><blockquote><ul><li>好账户：给你非常高的利率，随着年份增长利率还会上升</li><li>不错账户：给你有吸引力的利率，你增加存款也能赚利息</li><li>糟糕账户：给你不足的利率，还要求你不断加钱，才能拿到那些令人失望的回报&quot;</li></ul></blockquote><blockquote><p>&quot;航空业就是第三种。&quot;</p></blockquote><hr><h2 id="六、2013年-铁路与航空的本质差异" tabindex="-1">六、2013年：铁路与航空的本质差异 <a class="header-anchor" href="#六、2013年-铁路与航空的本质差异" aria-label="Permalink to &quot;六、2013年：铁路与航空的本质差异&quot;">​</a></h2><p>巴菲特在讨论完<a href="/03_companies/BNSF铁路.html">BNSF铁路</a>后，对比了铁路与航空的根本差异：</p><blockquote><p>&quot;<a href="/03_companies/BNSF铁路.html">BNSF铁路</a>承运约15%（按吨英里计算）的所有城际货物。用一加仑柴油运送一吨货物约500英里，承担同样工作的卡车消耗的燃料约为四倍。&quot;</p></blockquote><p>铁路具有定价权，航空没有；铁路资本回报稳定，航空永无止境地需要资本投入。</p><hr><h2 id="主题关联" tabindex="-1">主题关联 <a class="header-anchor" href="#主题关联" aria-label="Permalink to &quot;主题关联&quot;">​</a></h2>',38)),(e(),s(n,null,{default:l(()=>[q(o,{id:"mermaid-199",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E8%88%AA%E7%A9%BA%E5%85%AC%E5%8F%B8%E6%95%99%E8%AE%AD%5D%20--%3E%20B%5B%E7%94%9F%E6%84%8F%E6%A8%A1%E5%BC%8F%5D%0A%20%20%20%20A%20--%3E%20C%5B%E9%A3%8E%E9%99%A9%5D%0A%20%20%20%20A%20--%3E%20D%5B%E8%B5%84%E6%9C%AC%E9%85%8D%E7%BD%AE%5D%0A%20%20%20%20A%20--%3E%20E%5B%E9%94%99%E8%AF%AF%E4%B8%8E%E5%8F%8D%E6%80%9D%5D%0A%20%20%20%20A%20--%3E%20F%5B%E9%80%86%E5%90%91%E6%80%9D%E7%BB%B4%5D%0A"})]),fallback:l(()=>[...t[0]||(t[0]=[u(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<hr><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="/search.html?q=风险">风险</a> - 如何避免类似的资本配置错误</li><li><a href="/search.html?q=资本配置">资本配置</a> - 如何评估资本密集型行业</li><li><a href="/search.html?q=逆向思维">逆向思维</a> - 为什么航空公司的&quot;增长&quot;是陷阱</li><li><a href="/search.html?q=长期主义">长期主义</a> - 为什么要避开没有护城河的公司</li></ul><hr><p><em>本页面整理自<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>致股东信原文（1957-2024年），<a href="/search.html?q=慢慢变富的卡尔">慢慢变富的卡尔</a>编辑整理</em></p>',5))])}const A=r(c,[["render",d]]);export{E as __pageData,A as default};
